import { Kernel } from '@semantic-kernel/core';
import { SequentialPlanner } from '@semantic-kernel/agents';

import { performance } from 'perf_hooks';

const kernel = Kernel.create();
const planner = new SequentialPlanner(kernel);

async function measurePlanningLatency(goal: string) {
    const start = performance.now();
    const plan = await planner.createPlan(goal);
    const duration = performance.now() - start;

    if (duration > 5000) { // 5s threshold
        console.warn(`🚨 Planner latency: ${duration.toFixed(0)}ms`);
    }

    return plan;
}
