import { Kernel } from '@semantic-kernel/core';
import { OpenAIChatCompletion } from '@semantic-kernel/connectors-ai-openai';

const kernel = Kernel.create();

// Streaming reduces TTFB from 8s to 800ms
kernel.addChatService(
    'gpt-4-stream',
    new OpenAIChatCompletion(
        'gpt-4',
        { streaming: true }
    )
);

const planner = kernel.getService(SequentialPlanner);

// Plan generation feels instant
const stream = await planner.createPlanStream('research topic X');
for await (const chunk of stream) {
    process.stdout.write(chunk);
}
